import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { API } from "../api/base";
import "./CompanyAnalytics.scss";

export default function CompanyAnalytics() {
  const [analytics, setAnalytics] = useState(null);
  const token = localStorage.getItem("token");
  const navigate = useNavigate();

  useEffect(() => {
    document.body.classList.add("company-theme");
    document.body.classList.remove("hacker-theme");

    const fetchAnalytics = async () => {
      try {
        const res = await fetch(
          `${API}/api/company/analytics`,
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        const data = await res.json();
        setAnalytics(data);
      } catch (err) {
        console.error(err);
      }
    };

    fetchAnalytics();

    return () => {
      document.body.classList.remove("company-theme");
    };
  }, [token]);

  if (!analytics) return <div className="company-page">Loading...</div>;

  return (
    <div className="company-page">

      <div className="top-bar">
        <button
          className="back-btn"
          onClick={() => navigate("/company")}
        >
          ⬅ Back
        </button>

        <h1>Company Analytics</h1>
      </div>

      <div className="analytics-grid">

        <div className="stat-box">
          <h3>Total Bugs</h3>
          <p>{analytics.totalBugs}</p>
        </div>

        <div className="stat-box">
          <h3>Pending</h3>
          <p>{analytics.pendingBugs}</p>
        </div>

        <div className="stat-box">
          <h3>Approved</h3>
          <p>{analytics.approvedBugs}</p>
        </div>

        <div className="stat-box">
          <h3>Rejected</h3>
          <p>{analytics.rejectedBugs}</p>
        </div>

        <div className="stat-box">
          <h3>Total Paid</h3>
          <p>₹{analytics.totalPaid}</p>
        </div>

        <div className="stat-box wallet">
          <h3>Wallet Balance</h3>
          <p>₹{analytics.walletBalance}</p>
        </div>

      </div>

    </div>
  );
}
